     1вҶ’//! FORGE - Agent Orchestration Dashboard
     2вҶ’//!
     3вҶ’//! A terminal-based dashboard for managing FORGE AI worker agents.
     4вҶ’//!
     5вҶ’//! ## Usage
     6вҶ’//!
     7вҶ’//! ```bash
     8вҶ’//! # Start the TUI dashboard
     9вҶ’//! forge
    10вҶ’//!
    11вҶ’//! # With verbose logging
    12вҶ’//! forge -v
    13вҶ’//!
    14вҶ’//! # With debug mode (verbose tracing to ~/.forge/logs/forge.log in JSON format)
    15вҶ’//! forge --debug
    16вҶ’//!
    17вҶ’//! # With custom log directory
    18вҶ’//! forge --log-dir /path/to/logs/
    19вҶ’//!
    20вҶ’//! # Show version
    21вҶ’//! forge --version
    22вҶ’//! ```
    23вҶ’
    24вҶ’use std::io::Write;
    25вҶ’use std::panic;
    26вҶ’use std::process::ExitCode;
    27вҶ’
    28вҶ’use clap::{Parser, Subcommand};
    29вҶ’use forge_core::{LogGuard, StatusWriter, init_logging};
    30вҶ’use forge_init::{detection, generator, guidance, validator, wizard};
    31вҶ’use forge_tui::{App, ForgeConfig};
    32вҶ’use tracing::{error, info};
    33вҶ’
    34вҶ’/// FORGE Agent Orchestration Dashboard
    35вҶ’///
    36вҶ’/// A terminal-based interface for managing AI worker agents,
    37вҶ’/// monitoring task queues, and tracking costs.
    38вҶ’#[derive(Parser, Debug)]
    39вҶ’#[command(name = "forge")]
    40вҶ’#[command(author, version, about, long_about = None)]
    41вҶ’struct Cli {
    42вҶ’    /// Enable verbose logging (increases log level)
    43вҶ’    #[arg(short, long, action = clap::ArgAction::Count)]
    44вҶ’    verbose: u8,
    45вҶ’
    46вҶ’    /// Enable debug mode with verbose tracing output to ~/.forge/logs/forge.log
    47вҶ’    #[arg(long)]
    48вҶ’    debug: bool,
    49вҶ’
    50вҶ’    /// Directory for log files (defaults to ~/.forge/logs/)
    51вҶ’    #[arg(long)]
    52вҶ’    log_dir: Option<std::path::PathBuf>,
    53вҶ’
    54вҶ’    /// Subcommands
    55вҶ’    #[command(subcommand)]
    56вҶ’    command: Option<Commands>,
    57вҶ’}
    58вҶ’
    59вҶ’#[derive(Subcommand, Debug)]
    60вҶ’enum Commands {
    61вҶ’    /// Initialize FORGE configuration (first-time setup)
    62вҶ’    Init {
    63вҶ’        /// Run in non-interactive mode (for CI/automation)
    64вҶ’        /// Auto-selects first available backend or uses FORGE_CHAT_BACKEND env var
    65вҶ’        #[arg(long)]
    66вҶ’        non_interactive: bool,
    67вҶ’
    68вҶ’        /// Force re-initialization even if config exists
    69вҶ’        #[arg(long)]
    70вҶ’        force: bool,
    71вҶ’
    72вҶ’        /// Re-run setup on existing config (backs up config first)
    73вҶ’        /// Use this to change settings while preserving user data (logs, costs, status)
    74вҶ’        #[arg(long, conflicts_with = "force")]
    75вҶ’        reconfigure: bool,
    76вҶ’
    77вҶ’        /// Only detect available CLI tools and show results (dry run)
    78вҶ’        /// Does not modify any files
    79вҶ’        #[arg(long, conflicts_with_all = ["force", "reconfigure"])]
    80вҶ’        detect_tools: bool,
    81вҶ’    },
    82вҶ’
    83вҶ’    /// Update forge binary from a URL
    84вҶ’    Update {
    85вҶ’        /// URL to download the new binary from
    86вҶ’        url: String,
    87вҶ’
    88вҶ’        /// Expected SHA256 checksum of the binary
    89вҶ’        checksum: String,
    90вҶ’
    91вҶ’        /// Filename to save in staging (defaults to "forge")
    92вҶ’        #[arg(short, long, default_value = "forge")]
    93вҶ’        filename: String,
    94вҶ’    },
    95вҶ’
    96вҶ’    /// Rollback to the previous version
    97вҶ’    Rollback,
    98вҶ’
    99вҶ’    /// Clean the staging directory
   100вҶ’    CleanStaging,
   101вҶ’
   102вҶ’    /// Manage workers
   103вҶ’    Worker {
   104вҶ’        #[command(subcommand)]
   105вҶ’        action: WorkerAction,
   106вҶ’    },
   107вҶ’
   108вҶ’    /// Validate FORGE configuration
   109вҶ’    Validate {
   110вҶ’        /// Show detailed validation results
   111вҶ’        #[arg(long, short = 'v')]
   112вҶ’        verbose: bool,
   113вҶ’
   114вҶ’        /// Attempt automatic fixes for issues
   115вҶ’        #[arg(long)]
   116вҶ’        fix: bool,
   117вҶ’
   118вҶ’        /// Skip chat backend connectivity test
   119вҶ’        #[arg(long)]
   120вҶ’        skip_backend_test: bool,
   121вҶ’
   122вҶ’        /// Output results as JSON
   123вҶ’        #[arg(long)]
   124вҶ’        json: bool,
   125вҶ’    },
   126вҶ’}
   127вҶ’
   128вҶ’#[derive(Subcommand, Debug)]
   129вҶ’enum WorkerAction {
   130вҶ’    /// Pause a worker (stop claiming new tasks)
   131вҶ’    Pause {
   132вҶ’        /// Worker ID to pause, or "all" to pause all workers
   133вҶ’        id: String,
   134вҶ’    },
   135вҶ’
   136вҶ’    /// Resume a paused worker
   137вҶ’    Resume {
   138вҶ’        /// Worker ID to resume, or "all" to resume all workers
   139вҶ’        id: String,
   140вҶ’    },
   141вҶ’}
   142вҶ’
   143вҶ’fn main() -> ExitCode {
   144вҶ’    // CRITICAL: Check for rollback BEFORE parsing CLI or initializing anything
   145вҶ’    // This must be the first thing we do to detect crashes from previous updates
   146вҶ’    #[cfg(feature = "self-update")]
   147вҶ’    {
   148вҶ’        use forge_core::RollbackResult;
   149вҶ’
   150вҶ’        match forge_core::check_and_rollback() {
   151вҶ’            RollbackResult::RolledBack {
   152вҶ’                failed_version,
   153вҶ’                restored_version,
   154вҶ’            } => {
   155вҶ’                let restored = restored_version
   156вҶ’                    .map(|v| format!("v{}", v))
   157вҶ’                    .unwrap_or_else(|| "previous version".to_string());
   158вҶ’                eprintln!(
   159вҶ’                    "вҡ пёҸ  Update to v{} failed on startup - rolled back to {}",
   160вҶ’                    failed_version, restored
   161вҶ’                );
   162вҶ’                eprintln!("вқҢ Update failed, rolled back to previous version");
   163вҶ’                eprintln!("Please check ~/.forge/logs/forge.log for error details\n");
   164вҶ’                // Continue running with the rolled-back version
   165вҶ’            }
   166вҶ’            RollbackResult::Failed(err) => {
   167вҶ’                eprintln!("вқҢ Critical: Rollback failed: {}", err);
   168вҶ’                eprintln!("You may need to manually restore from backup\n");
   169вҶ’                // Continue anyway - better to try running than to abort
   170вҶ’            }
   171вҶ’            RollbackResult::NotNeeded => {
   172вҶ’                // Normal startup, no crash detected
   173вҶ’            }
   174вҶ’        }
   175вҶ’    }
   176вҶ’
   177вҶ’    // Mark that we're starting up (for crash detection on next run)
   178вҶ’    #[cfg(feature = "self-update")]
   179вҶ’    {
   180вҶ’        if let Err(e) = forge_core::mark_startup_in_progress() {
   181вҶ’            eprintln!("Warning: Failed to create startup marker: {}", e);
   182вҶ’            // Don't fail startup just because of this
   183вҶ’        }
   184вҶ’    }
   185вҶ’
   186вҶ’    let cli = Cli::parse();
   187вҶ’
   188вҶ’    // Initialize logging
   189вҶ’    let _guard = match setup_logging(&cli) {
   190вҶ’        Ok(guard) => guard,
   191вҶ’        Err(e) => {
   192вҶ’            eprintln!("Failed to initialize logging: {}", e);
   193вҶ’            return ExitCode::from(1);
   194вҶ’        }
   195вҶ’    };
   196вҶ’
   197вҶ’    // Check if this is a freshly exec'd process that needs to install itself
   198вҶ’    #[cfg(feature = "self-update")]
   199вҶ’    {
   200вҶ’        match forge_core::check_and_perform_self_install() {
   201вҶ’            Ok(Some(install_path)) => {
   202вҶ’                eprintln!("вң… Update installed successfully to: {}", install_path.display());
   203вҶ’                eprintln!("рҹҡҖ Restarting FORGE with new version...\n");
   204вҶ’                info!("Self-install completed to {:?}", install_path);
   205вҶ’                // Continue with normal startup
   206вҶ’            }
   207вҶ’            Ok(None) => {
   208вҶ’                // Normal startup, not an auto-restart
   209вҶ’            }
   210вҶ’            Err(e) => {
   211вҶ’                eprintln!("вқҢ Self-install failed: {}", e);
   212вҶ’                error!("Self-install error: {}", e);
   213вҶ’                return ExitCode::from(1);
   214вҶ’            }
   215вҶ’        }
   216вҶ’    }
   217вҶ’
   218вҶ’    #[cfg(not(feature = "self-update"))]
   219вҶ’    {
   220вҶ’        // No self-update feature, skip installation check
   221вҶ’    }
   222вҶ’
   223вҶ’    // Handle subcommands that don't require the TUI
   224вҶ’    if let Some(command) = &cli.command {
   225вҶ’        match command {
   226вҶ’            Commands::Init {
   227вҶ’                non_interactive,
   228вҶ’                force,
   229вҶ’                reconfigure,
   230вҶ’                detect_tools,
   231вҶ’            } => {
   232вҶ’                return handle_init_command(*non_interactive, *force, *reconfigure, *detect_tools);
   233вҶ’            }
   234вҶ’            Commands::Worker { action } => {
   235вҶ’                return handle_worker_action(action);
   236вҶ’            }
   237вҶ’            Commands::Validate {
   238вҶ’                verbose,
   239вҶ’                fix,
   240вҶ’                skip_backend_test,
   241вҶ’                json,
   242вҶ’            } => {
   243вҶ’                return handle_validate_command(*verbose, *fix, *skip_backend_test, *json);
   244вҶ’            }
   245вҶ’            _ => {
   246вҶ’                // Other commands fall through to TUI startup
   247вҶ’            }
   248вҶ’        }
   249вҶ’    }
   250вҶ’
   251вҶ’    // Install panic hook to ensure terminal cleanup
   252вҶ’    install_panic_hook();
   253вҶ’
   254вҶ’    // Check if onboarding is needed
   255вҶ’    if needs_onboarding() {
   256вҶ’        eprintln!("рҹҡҖ Welcome to FORGE!");
   257вҶ’        eprintln!("No configuration found. Running first-time setup...\n");
   258вҶ’
   259вҶ’        if let Err(e) = run_onboarding(false, None) {
   260вҶ’            eprintln!("вқҢ Onboarding failed: {}", e);
   261вҶ’            eprintln!("You can manually create ~/.forge/config.yaml or try again.");
   262вҶ’            return ExitCode::from(1);
   263вҶ’        }
   264вҶ’
   265вҶ’        eprintln!("\nвң… Setup complete! Starting FORGE dashboard...\n");
   266вҶ’    }
   267вҶ’
   268вҶ’    // Validate config file if it exists
   269вҶ’    if !needs_onboarding()
   270вҶ’        && let Err(e) = validate_config()
   271вҶ’    {
   272вҶ’        eprintln!("\n{}", e);
   273вҶ’        return ExitCode::from(1);
   274вҶ’    }
   275вҶ’
   276вҶ’    // Check for required dependencies
   277вҶ’    if !forge_core::check_dependencies() {
   278вҶ’        // check_dependencies already prints error messages
   279вҶ’        return ExitCode::from(1);
   280вҶ’    }
   281вҶ’
   282вҶ’    info!("Starting FORGE dashboard");
   283вҶ’
   284вҶ’    // Mark startup as successful (app initialized without crashing)
   285вҶ’    #[cfg(feature = "self-update")]
   286вҶ’    {
   287вҶ’        if let Err(e) = forge_core::mark_startup_successful() {
   288вҶ’            error!("Failed to mark startup as successful: {}", e);
   289вҶ’            // Don't fail just because of this
   290вҶ’        }
   291вҶ’    }
   292вҶ’
   293вҶ’    // Log terminal dimensions for debugging
   294вҶ’    if let Ok((cols, rows)) = crossterm::terminal::size() {
   295вҶ’        info!("Terminal size: {}x{} (columns x rows)", cols, rows);
   296вҶ’        eprintln!("Terminal size: {}x{} (columns x rows)", cols, rows);
   297вҶ’    } else {
   298вҶ’        error!("Failed to get terminal size");
   299вҶ’    }
   300вҶ’
   301вҶ’    // Run the TUI application
   302вҶ’    match run_app() {
   303вҶ’        Ok(()) => {
   304вҶ’            info!("FORGE dashboard exited normally");
   305вҶ’            ExitCode::SUCCESS
   306вҶ’        }
   307вҶ’        Err(e) => {
   308вҶ’            error!("FORGE dashboard error: {}", e);
   309вҶ’            eprintln!("Error: {}", e);
   310вҶ’            ExitCode::from(1)
   311вҶ’        }
   312вҶ’    }
   313вҶ’}
   314вҶ’
   315вҶ’/// Install a panic hook that restores the terminal before printing the panic message.
   316вҶ’///
   317вҶ’/// This ensures that even if the application panics while in raw mode with the
   318вҶ’/// alternate screen enabled, the terminal will be properly restored so the user
   319вҶ’/// can see the panic message and continue using their terminal.
   320вҶ’fn install_panic_hook() {
   321вҶ’    let original_hook = panic::take_hook();
   322вҶ’
   323вҶ’    panic::set_hook(Box::new(move |panic_info| {
   324вҶ’        // Attempt to restore terminal state
   325вҶ’        let _ = restore_terminal();
   326вҶ’
   327вҶ’        // Call the original panic hook to print the panic message
   328вҶ’        original_hook(panic_info);
   329вҶ’    }));
   330вҶ’}
   331вҶ’
   332вҶ’/// Restore terminal to its normal state.
   333вҶ’///
   334вҶ’/// This function is called both on normal exit and during panic handling.
   335вҶ’fn restore_terminal() -> std::io::Result<()> {
   336вҶ’    let mut stdout = std::io::stdout();
   337вҶ’
   338вҶ’    // Disable raw mode first
   339вҶ’    let _ = crossterm::terminal::disable_raw_mode();
   340вҶ’
   341вҶ’    // Leave alternate screen and disable mouse capture
   342вҶ’    crossterm::execute!(
   343вҶ’        stdout,
   344вҶ’        crossterm::terminal::LeaveAlternateScreen,
   345вҶ’        crossterm::event::DisableMouseCapture
   346вҶ’    )?;
   347вҶ’
   348вҶ’    // Show cursor
   349вҶ’    crossterm::execute!(stdout, crossterm::cursor::Show)?;
   350вҶ’
   351вҶ’    // Flush to ensure all escape sequences are written
   352вҶ’    stdout.flush()?;
   353вҶ’
   354вҶ’    Ok(())
   355вҶ’}
   356вҶ’
   357вҶ’/// Set up logging based on CLI arguments.
   358вҶ’fn setup_logging(cli: &Cli) -> forge_core::Result<LogGuard> {
   359вҶ’    // Initialize logging with the specified log directory
   360вҶ’    // Either --debug or -v/--verbose enables debug logging
   361вҶ’    let debug = cli.debug || cli.verbose > 0;
   362вҶ’    init_logging(cli.log_dir.clone(), debug)
   363вҶ’}
   364вҶ’
   365вҶ’/// Check if onboarding is needed (no config.yaml exists).
   366вҶ’fn needs_onboarding() -> bool {
   367вҶ’    let forge_dir = get_forge_dir();
   368вҶ’    let config_path = forge_dir.join("config.yaml");
   369вҶ’    !config_path.exists()
   370вҶ’}
   371вҶ’
   372вҶ’/// Get the FORGE directory path (~/.forge).
   373вҶ’fn get_forge_dir() -> std::path::PathBuf {
   374вҶ’    dirs::home_dir()
   375вҶ’        .expect("Could not determine home directory")
   376вҶ’        .join(".forge")
   377вҶ’}
   378вҶ’
   379вҶ’/// Run the onboarding flow.
   380вҶ’///
   381вҶ’/// # Arguments
   382вҶ’///
   383вҶ’/// * `non_interactive` - If true, suppress output and auto-select backend
   384вҶ’/// * `preferred_backend` - Optional backend to use (from FORGE_CHAT_BACKEND env var)
   385вҶ’fn run_onboarding(
   386вҶ’    non_interactive: bool,
   387вҶ’    preferred_backend: Option<&str>,
   388вҶ’) -> Result<(), Box<dyn std::error::Error>> {
   389вҶ’    info!(
   390вҶ’        "Starting onboarding flow (non_interactive={}, preferred_backend={:?})",
   391вҶ’        non_interactive, preferred_backend
   392вҶ’    );
   393вҶ’
   394вҶ’    // Detect CLI tools with diagnostics
   395вҶ’    if !non_interactive {
   396вҶ’        eprintln!("рҹ”Қ Detecting available CLI tools...");
   397вҶ’    }
   398вҶ’    let (tools, diagnostics) = detection::detect_cli_tools_with_diagnostics()?;
   399вҶ’
   400вҶ’    // Filter to only show tools that are ready to use
   401вҶ’    let ready_tools: Vec<_> = tools.iter().filter(|t| t.is_ready()).collect();
   402вҶ’
   403вҶ’    if ready_tools.is_empty() {
   404вҶ’        if non_interactive {
   405вҶ’            // In non-interactive mode, output to stderr and exit
   406вҶ’            eprintln!("error: No compatible CLI tools available");
   407вҶ’            eprintln!("Install one of: claude (Claude Code), opencode, aider");
   408вҶ’        } else {
   409вҶ’            // Use the guidance module to show detailed instructions
   410вҶ’            eprint!("{}", guidance::generate_guidance(Some(&diagnostics)));
   411вҶ’        }
   412вҶ’        return Err("No compatible CLI tools available".into());
   413вҶ’    }
   414вҶ’
   415вҶ’    // Select the backend to use
   416вҶ’    let selected_tool: detection::CliToolDetection = if let Some(backend) = preferred_backend {
   417вҶ’        // Try to find the specified backend
   418вҶ’        let normalized_backend = normalize_backend_name(backend);
   419вҶ’        let found = tools.iter().find(|t| {
   420вҶ’            let tool_name = normalize_backend_name(&t.name);
   421вҶ’            tool_name == normalized_backend
   422вҶ’        });
   423вҶ’
   424вҶ’        match found {
   425вҶ’            Some(tool) => {
   426вҶ’                if !tool.is_ready() {
   427вҶ’                    eprintln!(
   428вҶ’                        "error: Backend '{}' is not ready: {}",
   429вҶ’                        backend,
   430вҶ’                        tool.status_message()
   431вҶ’                    );
   432вҶ’                    if tool.status == detection::ToolStatus::MissingApiKey
   433вҶ’                        && let Some(env_var) = &tool.api_key_env_var
   434вҶ’                    {
   435вҶ’                        eprintln!("Set the {} environment variable and try again", env_var);
   436вҶ’                    }
   437вҶ’                    return Err(format!("Backend '{}' is not ready", backend).into());
   438вҶ’                }
   439вҶ’                tool.clone()
   440вҶ’            }
   441вҶ’            None => {
   442вҶ’                eprintln!("error: Backend '{}' not found", backend);
   443вҶ’                eprintln!(
   444вҶ’                    "Available backends: {}",
   445вҶ’                    tools
   446вҶ’                        .iter()
   447вҶ’                        .map(|t| t.name.as_str())
   448вҶ’                        .collect::<Vec<_>>()
   449вҶ’                        .join(", ")
   450вҶ’                );
   451вҶ’                return Err(format!("Backend '{}' not found", backend).into());
   452вҶ’            }
   453вҶ’        }
   454вҶ’    } else if non_interactive {
