   577вҶ’/// Normalize backend name for comparison.
   578вҶ’///
   579вҶ’/// Maps common aliases to canonical names:
   580вҶ’/// - "claude", "claude-code", "claudecode" -> "claude-code"
   581вҶ’/// - "opencode" -> "opencode"
   582вҶ’/// - "aider" -> "aider"
   583вҶ’fn normalize_backend_name(name: &str) -> String {
   584вҶ’    let lower = name.to_lowercase();
   585вҶ’    match lower.as_str() {
   586вҶ’        "claude" | "claude-code" | "claudecode" => "claude-code".to_string(),
   587вҶ’        other => other.to_string(),
   588вҶ’    }
   589вҶ’}
