   591вҶ’/// Handle the `forge init` command.
   592вҶ’fn handle_init_command(non_interactive: bool, force: bool, reconfigure: bool, detect_tools: bool) -> ExitCode {
   593вҶ’    info!(
   594вҶ’        "Handling init command (non_interactive={}, force={}, reconfigure={}, detect_tools={})",
   595вҶ’        non_interactive, force, reconfigure, detect_tools
   596вҶ’    );
   597вҶ’
   598вҶ’    // Handle --detect-tools: dry run that only shows detection results
   599вҶ’    if detect_tools {
   600вҶ’        return handle_detect_tools_command();
   601вҶ’    }
   602вҶ’
   603вҶ’    let forge_dir = get_forge_dir();
   604вҶ’    let config_path = forge_dir.join("config.yaml");
   605вҶ’
   606вҶ’    // Handle --reconfigure: backup existing config before re-running setup
   607вҶ’    if reconfigure {
   608вҶ’        if !config_path.exists() {
   609вҶ’            if non_interactive {
   610вҶ’                eprintln!("error: No configuration found to reconfigure");
   611вҶ’                eprintln!("Use 'forge init' to create initial configuration");
   612вҶ’            } else {
   613вҶ’                eprintln!("No configuration found. Running first-time setup instead...\n");
   614вҶ’            }
   615вҶ’            // Fall through to normal setup since there's nothing to reconfigure
   616вҶ’        } else {
   617вҶ’            // Backup existing config before proceeding
   618вҶ’            if let Err(e) = backup_config(&forge_dir, &config_path) {
   619вҶ’                eprintln!("вқҢ Failed to backup config: {}", e);
   620вҶ’                return ExitCode::from(1);
   621вҶ’            }
   622вҶ’            if !non_interactive {
   623вҶ’                eprintln!("рҹ“Ұ Existing configuration backed up\n");
   624вҶ’            }
   625вҶ’        }
   626вҶ’    } else if !force && config_path.exists() {
   627вҶ’        // Neither --force nor --reconfigure: don't overwrite existing config
   628вҶ’        if non_interactive {
   629вҶ’            eprintln!(
   630вҶ’                "error: Configuration already exists at {}",
   631вҶ’                config_path.display()
   632вҶ’            );
   633вҶ’            eprintln!("Use --force to overwrite existing configuration");
   634вҶ’            eprintln!("Use --reconfigure to backup and re-run setup");
   635вҶ’            return ExitCode::from(1);
   636вҶ’        } else {
   637вҶ’            eprintln!(
   638вҶ’                "Configuration already exists at {}",
   639вҶ’                config_path.display()
   640вҶ’            );
   641вҶ’            eprintln!("Use --force to overwrite existing configuration");
   642вҶ’            eprintln!("Use --reconfigure to backup and re-run setup");
   643вҶ’            return ExitCode::SUCCESS;
   644вҶ’        }
   645вҶ’    }
   646вҶ’
   647вҶ’    // Get preferred backend from environment variable
   648вҶ’    let preferred_backend = std::env::var("FORGE_CHAT_BACKEND").ok();
   649вҶ’
   650вҶ’    if non_interactive {
   651вҶ’        // Non-interactive mode: quiet output, clear error messages to stderr
   652вҶ’        match run_onboarding(true, preferred_backend.as_deref()) {
   653вҶ’            Ok(()) => ExitCode::SUCCESS,
   654вҶ’            Err(_) => ExitCode::from(1),
   655вҶ’        }
   656вҶ’    } else {
   657вҶ’        // Interactive mode: show welcome message and full output
   658вҶ’        eprintln!("рҹҡҖ FORGE Setup");
   659вҶ’        eprintln!();
   660вҶ’
   661вҶ’        match run_onboarding(false, preferred_backend.as_deref()) {
   662вҶ’            Ok(()) => {
   663вҶ’                eprintln!("\nвң… Setup complete!");
   664вҶ’                ExitCode::SUCCESS
   665вҶ’            }
   666вҶ’            Err(e) => {
   667вҶ’                eprintln!("вқҢ Setup failed: {}", e);
   668вҶ’                ExitCode::from(1)
   669вҶ’            }
   670вҶ’        }
   671вҶ’    }
   672вҶ’}
   673вҶ’
   674вҶ’/// Backup existing config.yaml before reconfiguration.
   675вҶ’///
   676вҶ’/// Creates a timestamped backup to preserve user's previous settings.
   677вҶ’/// Keeps logs, costs database, and status files intact.
   678вҶ’fn backup_config(forge_dir: &std::path::Path, config_path: &std::path::Path) -> Result<std::path::PathBuf, Box<dyn std::error::Error>> {
   679вҶ’    let timestamp = chrono::Local::now().format("%Y%m%d_%H%M%S");
   680вҶ’    let backup_path = forge_dir.join(format!("config.yaml.backup.{}", timestamp));
   681вҶ’
   682вҶ’    std::fs::copy(config_path, &backup_path)?;
   683вҶ’    info!("Backed up config to: {}", backup_path.display());
   684вҶ’
   685вҶ’    // Check for launcher scripts that might have custom modifications
   686вҶ’    let launchers_dir = forge_dir.join("launchers");
   687вҶ’    if launchers_dir.exists()
   688вҶ’        && let Ok(entries) = std::fs::read_dir(&launchers_dir)
   689вҶ’    {
   690вҶ’        for entry in entries.flatten() {
   691вҶ’            let path = entry.path();
   692вҶ’            if path.is_file() {
   693вҶ’                // Check if the file contains any comments that suggest custom modifications
   694вҶ’                if let Ok(content) = std::fs::read_to_string(&path) {
   695вҶ’                    if content.contains("# CUSTOM:") || content.contains("# USER:") || content.contains("# Modified by") {
   696вҶ’                        eprintln!("вҡ пёҸ  Warning: {} may contain custom modifications", path.display());
   697вҶ’                        // Backup the launcher script too
   698вҶ’                        let launcher_backup = forge_dir.join(format!(
   699вҶ’                            "launchers/{}.backup.{}",
   700вҶ’                            entry.file_name().to_string_lossy(),
   701вҶ’                            timestamp
   702вҶ’                        ));
   703вҶ’                        let _ = std::fs::copy(&path, &launcher_backup);
   704вҶ’                    }
   705вҶ’                }
   706вҶ’            }
   707вҶ’        }
   708вҶ’    }
   709вҶ’
   710вҶ’    Ok(backup_path)
   711вҶ’}
