   713вҶ’/// Handle the `forge init --detect-tools` command.
   714вҶ’///
   715вҶ’/// Runs CLI tool detection and displays results without modifying any files.
   716вҶ’fn handle_detect_tools_command() -> ExitCode {
   717вҶ’    info!("Running CLI tool detection (dry run)");
   718вҶ’
   719вҶ’    eprintln!("рҹ”Қ Detecting available CLI tools...\n");
   720вҶ’
   721вҶ’    match detection::detect_cli_tools_with_diagnostics() {
   722вҶ’        Ok((tools, diagnostics)) => {
   723вҶ’            // Display all detected tools
   724вҶ’            if tools.is_empty() {
   725вҶ’                eprintln!("No CLI tools found.\n");
   726вҶ’            } else {
   727вҶ’                eprintln!("Detected CLI tools:\n");
   728вҶ’                for tool in &tools {
   729вҶ’                    let status_icon = match tool.status {
   730вҶ’                        detection::ToolStatus::Ready => "вң…",
   731вҶ’                        detection::ToolStatus::MissingApiKey => "вҡ пёҸ ",
   732вҶ’                        detection::ToolStatus::IncompatibleVersion => "вқҢ",
   733вҶ’                        detection::ToolStatus::NotExecutable => "вқҢ",
   734вҶ’                    };
   735вҶ’
   736вҶ’                    eprintln!("  {} {} ({})", status_icon, tool.name, tool.status_message());
   737вҶ’                    eprintln!("      Path: {}", tool.binary_path.display());
   738вҶ’                    if let Some(version) = &tool.version {
   739вҶ’                        eprintln!("      Version: {}", version);
   740вҶ’                    }
   741вҶ’                    eprintln!("      Headless: {} | Skip-Perms: {}",
   742вҶ’                        if tool.headless_support { "yes" } else { "no" },
   743вҶ’                        if tool.skip_permissions { "yes" } else { "no" }
   744вҶ’                    );
   745вҶ’                    if tool.api_key_required {
   746вҶ’                        let key_status = if tool.api_key_detected { "вң… found" } else { "вқҢ missing" };
   747вҶ’                        if let Some(env_var) = &tool.api_key_env_var {
   748вҶ’                            eprintln!("      API Key: {} ({})", key_status, env_var);
   749вҶ’                        } else {
   750вҶ’                            eprintln!("      API Key: {}", key_status);
   751вҶ’                        }
   752вҶ’                    }
   753вҶ’                    eprintln!();
   754вҶ’                }
   755вҶ’            }
   756вҶ’
   757вҶ’            // Display diagnostics about rejected/not-found tools
   758вҶ’            if !diagnostics.rejections.is_empty() {
   759вҶ’                eprintln!("Detection details:");
   760вҶ’                for rejection in &diagnostics.rejections {
   761вҶ’                    match &rejection.reason {
   762вҶ’                        guidance::RejectionReason::NotFound => {
   763вҶ’                            eprintln!("  вҖў {} - not found in PATH", rejection.tool_name);
   764вҶ’                        }
   765вҶ’                        guidance::RejectionReason::MissingApiKey { env_var, .. } => {
   766вҶ’                            eprintln!("  вҖў {} - missing API key ({})", rejection.tool_name, env_var);
   767вҶ’                        }
   768вҶ’                        guidance::RejectionReason::IncompatibleVersion { version, missing_feature, .. } => {
   769вҶ’                            let ver = version.as_deref().unwrap_or("unknown");
   770вҶ’                            eprintln!("  вҖў {} {} - incompatible: {}", rejection.tool_name, ver, missing_feature);
   771вҶ’                        }
   772вҶ’                        guidance::RejectionReason::NotExecutable(_) => {
   773вҶ’                            eprintln!("  вҖў {} - not executable", rejection.tool_name);
   774вҶ’                        }
   775вҶ’                    }
   776вҶ’                }
   777вҶ’                eprintln!();
   778вҶ’            }
   779вҶ’
   780вҶ’            // Summary
   781вҶ’            let ready_count = tools.iter().filter(|t| t.is_ready()).count();
   782вҶ’            if ready_count > 0 {
   783вҶ’                eprintln!("вң… {} tool(s) ready for use", ready_count);
   784вҶ’                eprintln!("   Run 'forge init' to configure");
   785вҶ’            } else {
   786вҶ’                eprintln!("вқҢ No compatible tools ready");
   787вҶ’                eprintln!("   Install Claude Code, OpenCode, or configure API keys");
   788вҶ’            }
   789вҶ’
   790вҶ’            ExitCode::SUCCESS
   791вҶ’        }
   792вҶ’        Err(e) => {
   793вҶ’            eprintln!("вқҢ Detection failed: {}", e);
   794вҶ’            ExitCode::from(1)
   795вҶ’        }
   796вҶ’    }
   797вҶ’}
