   799вҶ’/// Validate the config file and offer recovery if invalid.
   800вҶ’fn validate_config() -> Result<(), String> {
   801вҶ’    use std::io::{self, Write};
   802вҶ’
   803вҶ’    match ForgeConfig::load_with_error() {
   804вҶ’        Ok(_config) => {
   805вҶ’            info!("Configuration validated successfully");
   806вҶ’            Ok(())
   807вҶ’        }
   808вҶ’        Err(e) => {
   809вҶ’            // Format the error with line/column information
   810вҶ’            eprintln!("вқҢ Configuration Error");
   811вҶ’            eprintln!();
   812вҶ’
   813вҶ’            let path_str = e.path().map(|p| p.display().to_string())
   814вҶ’                .unwrap_or_else(|| "~/.forge/config.yaml".to_string());
   815вҶ’
   816вҶ’            if let (Some(line), Some(col)) = (e.line_number(), e.column_number()) {
   817вҶ’                eprintln!("  File: {}", path_str);
   818вҶ’                eprintln!("  Line: {}, Column: {}", line, col);
   819вҶ’                eprintln!("  Error: {}", e);
   820вҶ’            } else {
   821вҶ’                eprintln!("  {}", e);
   822вҶ’            }
   823вҶ’            eprintln!();
   824вҶ’
   825вҶ’            // Offer recovery options
   826вҶ’            eprintln!("Recovery options:");
   827вҶ’            eprintln!("  1) Reset to default configuration (creates backup)");
   828вҶ’            eprintln!("  2) Use defaults without modifying file (temporary)");
   829вҶ’            eprintln!("  3) Exit and fix manually");
   830вҶ’            eprintln!();
   831вҶ’            eprint!("Choose option [1-3]: ");
   832вҶ’            io::stdout().flush().map_err(|e| e.to_string())?;
   833вҶ’
   834вҶ’            let mut choice = String::new();
   835вҶ’            io::stdin().read_line(&mut choice).map_err(|e| e.to_string())?;
   836вҶ’
   837вҶ’            match choice.trim() {
   838вҶ’                "1" => {
   839вҶ’                    if let Err(e) = reset_config_to_defaults() {
   840вҶ’                        return Err(format!("Failed to reset config: {}", e));
   841вҶ’                    }
   842вҶ’                    eprintln!("вң… Configuration reset to defaults");
   843вҶ’                    eprintln!("   Previous config backed up");
   844вҶ’                    eprintln!();
   845вҶ’                    Ok(())
   846вҶ’                }
   847вҶ’                "2" => {
   848вҶ’                    eprintln!("вҡ пёҸ  Using default configuration (file not modified)");
   849вҶ’                    eprintln!("   Fix the config file manually or delete it to regenerate");
   850вҶ’                    eprintln!();
   851вҶ’                    Ok(())
   852вҶ’                }
   853вҶ’                "3" | "" => {
   854вҶ’                    Err("Exiting. Please fix the config file and try again.".to_string())
   855вҶ’                }
   856вҶ’                _ => {
   857вҶ’                    Err("Invalid choice. Exiting.".to_string())
   858вҶ’                }
   859вҶ’            }
   860вҶ’        }
   861вҶ’    }
   862вҶ’}
